// Daily self-correction: ask the portal to re-read recent WhatsApp messages, catch orders that were
// filed as chatter, and apply correction messages — auto-applying only the high-confidence ones. The
// portal handles auth via the shared secret. Everything it does is visible on the Admin -> Data page.
const base = $env.PORTAL_BASE_URL;
const secret = $env.WASENDER_WEBHOOK_SECRET;
let result = { applied: 0 };
try {
  result = await this.helpers.httpRequest({ method: 'POST', url: base + '/api/admin/reprocess?key=' + encodeURIComponent(secret) + '&auto=1', body: {}, json: true });
} catch (e) { result = { error: String(e && e.message || e) }; }
return [{ json: result }];
